VALUES
  ('fire-eq-eng-moex-00733', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防火牆及防火水幕設置基準之規定，某儲槽儲存閃火點 90℃之公共危險物品，且儲槽水平剖面最大直 徑為8公尺，其假想火面高度為幾公尺？', '["8公尺", "12公尺", "16公尺", "24公尺"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00734', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能試驗基準，有關防焰物品或其材料之防焰性能之規定，下列何者正確？①餘燃時間：展示用', '["餘焰時間：展示用廣告板不得超過15秒", "碳化面積：展示用廣告板不得超 過100平方公分", "接焰次數：具熱熔融性之纖維製品應達三次以上", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00735', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能認證實施要點，有關防焰性能試驗之產品試樣規格之規定，下列何者正確？①室內展示用廣', '["地毯等地坪舖設物：1平方公尺以上", "窗簾、布幕，須經水洗及乾洗處 理者：2平方公尺以上", "布製折屏或百葉窗簾：2平方公尺以上", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00736', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防幫浦加壓送水裝置等及配管摩擦損失計算基準之規定，下列何者正確？', '["幫浦所消耗之動力，在額定出水量110%時，其軸動力不得超過馬達額定輸出馬力之150%", "幫浦本體必須能耐最高水壓之1.5倍以上，且加壓2分鐘後，各部位仍無洩漏現象才算合格", "電動機在額定輸出連續運轉6小時後，不得發生異狀", "防止水溫上升用之排放管應使用口徑15mm以上者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00737', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，下列何種場所或樓層，應設置自動撒水設備？', '["總樓地板面積200平方公尺之護理之家機構", "總樓地板面積500平方公尺以上之地下建築物", "15層建築物之6樓層，總樓地板面積200平方公尺之戲院", "9層建築物之3樓層，總樓地板面積250平方公尺之俱樂部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00738', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築法之規定，下列何者正確？', '["非供公眾使用建築物之室內裝修應申請審查許可", "直轄市、縣（市）（局）主管建築機關應自收到申請拆除執照書件之日起10日內審查完竣，合於規定 者，發給拆除執照", "建築物在施工中，鄰接其他建築物施行挖土工程時，對該鄰接建築物應視需要作防護其傾斜之措施。 挖土深度在1公尺以上者，其防護措施之設計圖樣及說明書，應於申請建造執照或雜項執照時一併送審", "2層以上建築物施工時，其施工部分距離道路境界線或基地境界線不足2.5公尺者，應設置防止物體墜 落之適當圍籬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00739', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編之規定，有關建築技術用語之定義，下列何者正確？', '["基地地面：基地整地完竣後，建築物外牆與地面接觸最低一側之水平面；基地地面高低相差超過 3 公 尺，以每相差3公尺之水平面為該部分基地地面", "耐燃材料：經中央主管建築機關認定符合耐燃二級之材料", "無窗戶居室：樓地板面積超過30平方公尺之居室，其天花板或天花板下方80公分範圍以內之有效通 風面積未達樓地板面積2%者", "集合住宅：具有共同基地及共同空間或設備。並有二個住宅單位以上之建築物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00740', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編，有關防火門窗構造之規定，下列何者正確？', '["防火門窗周邊15公分範圍內之牆壁應以耐燃材料建造", "防火門之門扇寬度應在75公分以上，高度應在180公分以上", "常時關閉式之防火門，單一門扇面積不得超過5平方公尺", "常時開放式之防火門，採用防火捲門者，應附設門扇寬度在70公分以上，高度在180公分以上之防火門"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00741', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依緊急電源容量計算基準之規定，下列何者正確？', '["同一建築基地之不同場所，其各類場所之消防安全設備緊急電源負載總容量，小於供給其最大場所之 負載所需之輸出容量時，得共用緊急電源，由一緊急發電機設備供給電力", "一場所設置二種以上之消防安全設備同時啟動時，設有能按次序逐次於10秒內供給消防安全設備電力 之裝置時，得免計入瞬時全負載投入之輸出容量", "蓄電池容量之計算需先決定維護因數、放電時間與放電電流、容許最高電壓、最高蓄電池溫度等四項 條件", "發電機與原動機組合為緊急發電機組，其整合率（MR）應大於1"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00742', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則設計施工編之規定，建築物在2樓以上，第10層以下之各樓層，應設置緊急進口，有關 其構造之敘述，下列何者正確？', '["進口應設面臨道路或寬度在5公尺以上通路之各層外牆面", "進口之間隔不得大於50公尺", "進口之寬度應在75公分以上，高度應在1.2公尺以上。其開口之下端應距離樓地板面120公分範圍以內", "進口外應設置陽台，其寬度應為1公尺以上，長度4公尺以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
